"""
mkt-christ layer — Acts chapters 14–15
Output: data/commentary/mkt-christ/acts.json
Run: python3 scripts/zc-christ-acts-14-15.py
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Merge new verse entries without overwriting already-present keys — safe to re-run.
    # CHANGE? If commentary JSON structure changes from {ch:{v:html}}, update this traversal.
    # VERIFY: Re-running the script should produce identical output (no duplicate or overwritten entries).
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ACTS_CH = {
"14": {
"1": "<p>Iconium repeats the synagogue pattern of Pisidian Antioch: a large number of Jews and Greeks believe. The mission's consistent method — synagogue first, then the wider city — reflects Jesus's own pattern of beginning with Israel before extending to Gentiles (Matt 10:5–6 in the limited commission; Luke 4:16–30 in the programmatic Nazareth scene). Each city's synagogue is both mission entry point and flashpoint for the division Jesus predicted: 'Do you think that I have come to give peace on earth? No, I tell you, but rather division' (Luke 12:51).</p>",
"2": "<p>The 'unbelieving Jews' who 'stirred up the Gentiles and poisoned their minds' enact the opposition pattern that Jesus warned the disciples about: 'you will be hated by all for my name's sake' (Luke 21:17). The two-stage opposition — first synagogue resistance, then broader civic agitation — follows the same escalation that accompanied Jesus's own ministry (from scribal criticism to Sanhedrin condemnation). Paul and Barnabas inherit the opposition their Lord received.</p>",
"3": "<p>'So they remained for a long time, speaking boldly for the Lord, who bore witness to the word of his grace, granting signs and wonders to be done by their hands.' The Lord 'bearing witness to the word of his grace' through signs and wonders is the fulfillment of Mark 16:20 (the longer ending): 'the Lord worked with them and confirmed the message by accompanying signs.' The risen Lord actively validates the apostolic proclamation — the mission is not merely human speech supported by miracles but the Lord's own witness through his apostles' mouths and hands.</p>",
"4": "<p>The division in Iconium — 'some sided with the Jews and some with the apostles' — enacts Jesus's prediction in Luke 12:52–53: 'from now on in one house there will be five divided, three against two and two against three.' The risen Lord's proclamation through his apostles does not produce immediate universal acceptance but the dividing of communities according to their response to the word. The division is itself a sign of the word's power: it does not leave people indifferent but demands a response.</p>",
"5": "<p>The plot to stone Paul and Barnabas — involving both Gentiles and Jews and their rulers — is the same cross-community opposition that condemned Jesus: Herod and Pilate, Jews and Romans cooperating against the Lord's anointed (Acts 4:27). The risen Lord's witnesses face the same cross-partisan opposition their master faced — not because they are threats to public order but because the word they proclaim is a claim on every human loyalty.</p>",
"6": "<p>The flight to Lystra and Derbe is the pattern of strategic withdrawal Jesus modeled and commanded: 'When they persecute you in one town, flee to the next' (Matt 10:23). The mission's continuation despite opposition reflects the risen Lord's guarantee: 'I will build my church, and the gates of hell shall not prevail against it' (Matt 16:18). Each city of flight is a new field of proclamation; the opposition that drives the apostles forward serves the mission's expansion.</p>",
"7": "<p>'And there they continued to preach the gospel' — the imperfect tense (euangelizomenoi) indicates continuous activity: they kept on preaching. The persistence of proclamation under pressure fulfills Jesus's commission to 'proclaim the gospel to the whole creation' (Mark 16:15) — a commission whose scope requires the willingness to move and keep moving regardless of opposition. The gospel's universality requires apostolic mobility.</p>",
"8": "<p>The lame man at Lystra — 'crippled from birth, who had never walked' — is the same profile as the man at the Beautiful Gate (Acts 3:2: 'lame from birth'). The identical circumstances establish a pattern: the risen Jesus's power, exercised at Pentecost through Peter and at Lystra through Paul, heals the same category of impossible disability. The healing pattern is the continuation of Jesus's healing ministry (Luke 7:22; Isa 35:6 — 'the lame man leaps like a deer') now operating through his apostles.</p>",
"9": "<p>Paul sees that the lame man 'had faith to be made well' (pistin tou sōthēnai) — the faith-healing connection mirrors Jesus's healings: 'your faith has made you well' (Luke 8:48; 17:19; 18:42). The apostle's discernment of faith before the healing act echoes Jesus's observation of faith before his healings (Mark 2:5: 'when Jesus saw their faith'; Luke 5:20). The risen Lord's healing power, mediated through Paul, operates on the same principle of faith that governed Jesus's healing ministry.</p>",
"10": "<p>'Stand upright on your feet' — Paul's command echoes both Jesus's healing commands ('Rise and walk,' Luke 5:23; 'Rise and go,' 17:19) and the angelic commands in Acts (5:20: 'Stand and go'; 12:7: 'Rise quickly'). The rising of the lame man is a mini-resurrection — from permanent disability to full mobility — enacted through the name of the one who said 'I am the resurrection and the life' (John 11:25). The man 'sprang up and began walking' — the same immediate completeness of Jesus's healings.</p>",
"11": "<p>The Lystra crowd's identification of Barnabas as Zeus and Paul as Hermes reflects both the Lycaonian mythological context and the profound human tendency to divinize extraordinary power. The crowd does not conclude 'God has visited his people' (as in Luke 7:16 after Jesus's healings in Jewish context) but reaches for their nearest theological categories — Greek polytheism. The healing demonstrates power that exceeds human explanation; the crowds explain it by the nearest framework available to them, which happens to be wrong.</p>",
"12": "<p>Barnabas as Zeus (the chief god) and Paul as Hermes (the divine messenger and speaker) inverts the actual situation: Barnabas is the senior companion, Paul the primary speaker. The crowd's assignment reveals both their perspective (Hermes = the one who talks) and their misidentification of the source. Hermes was the gods' messenger and the patron of eloquence; Paul is the risen Lord's messenger and herald — a genuine divine message-bringer, but representing a very different Lord than the one the crowd imagined.</p>",
"13": "<p>The priest of Zeus brings oxen and garlands to offer sacrifice to Barnabas and Paul — the highest honor possible in the Hellenistic religious system. The response of Paul and Barnabas (vv. 14–18) is the clearest anti-idolatry proclamation in Acts, anticipating Paul's Athens speech (17:22–31) and his characterization of pagan religion in Romans 1:23–25. The risen Lord's apostles refuse honor that belongs to God alone — consistent with Peter's refusal of Cornelius's prostration (10:26) and the angel's refusal of John's worship (Rev 19:10).</p>",
"14": "<p>Tearing their garments — the Jewish sign of grief and horror at blasphemy (cf. Matt 26:65 at Jesus's trial; Acts 22:23 at Paul's arrest). Paul and Barnabas react to the crowd's worship with the same symbolic gesture used by the high priest at Jesus's trial: tearing clothes before what is perceived as an offense against God's honor. The reversal is complete: Paul refuses the divine honor that the high priest accused Jesus of claiming. Paul and Barnabas refuse what Herod Agrippa accepted and was destroyed for accepting (Acts 12:23).</p>",
"15": "<p>'Men, why are you doing these things? We also are men, of like nature with you.' The declaration of apostolic humanity directly counters the divine identification: Paul and Barnabas are not gods but human beings in the same condition as the crowd. 'We bring you good news, that you should turn from these vain things to a living God, who made the heaven and the earth and the sea and all that is in them.' The sermon's structure — turn from idols to the living God who made everything — is the fundamental pre-Christian proclamation that clears the ground for the gospel. The 'living God' who 'made all things' is the God who raised Jesus from the dead.</p>",
"16": "<p>'In past generations he allowed all the nations to walk in their own ways' — the same point Peter made to Cornelius (Acts 10:34–35) and Paul will make in Athens (17:30). God's patient tolerance of Gentile ignorance is not approval but forbearance — the time of ignorance is now ending with the proclamation of the risen Christ. The 'past generations' were not abandoned by God but were allowed to follow their own path until the appointed time of the revelation of the Son.</p>",
"17": "<p>'Yet he did not leave himself without witness, for he did good by giving you rains from heaven and fruitful seasons, satisfying your hearts with food and gladness.' The witness of creation — rain, harvest, food, gladness — is Paul's argument that even the Gentiles who did not know the name of Jesus were not without divine testimony. Jesus had said: 'He makes his sun rise on the evil and on the good, and sends rain on the just and on the unjust' (Matt 5:45). The God who reveals himself in creation now reveals himself fully in the risen Son.</p>",
"18": "<p>'Even with these words they scarcely restrained the people from offering sacrifice to them.' The difficulty of preventing the sacrifice — even after Paul's passionate sermon — illustrates the depth of religious instinct in human communities: the encounter with healing power triggers worship, and redirecting worship from the event to the one true God requires persistent effort. The risen Lord's apostles face not hostility here but overwhelming and misdirected veneration — a different challenge that requires the same christocentric correction.</p>",
"19": "<p>Jews from Antioch and Iconium arrive and persuade the crowd — the crowd that moments before wanted to sacrifice to Paul now stones him. The dramatic reversal from divine honor to stoning encapsulates the pattern of Jesus's own reception: 'Hosanna' on Sunday, 'Crucify him' on Friday. The crowd's instability — veneration to murderous rejection in a single chapter — reflects the same crowd dynamics that surrounded Jesus. Paul's stoning 'to death' (or near death) and dragging outside the city enacts the passion pattern: suffering, apparent death, and what follows.</p>",
"20": "<p>'But when the disciples gathered around him, he rose up' — the Greek anastropheis (having risen up, turned about) carries the weight of the rising pattern in Acts. Paul's disciples gather around what they expect to be a dead man; Paul rises. Whether this was miraculous recovery or survival of injuries, Luke presents it in the resurrection pattern language: the disciples gather as the women gathered at the tomb; Paul rises as the Lord rose; he enters the city rather than fleeing. The 'death and resurrection' at Lystra mirrors the master's pattern.</p>",
"21": "<p>The mission to Derbe produces 'many disciples' — the word behind disciples (mathēteuō) is the commission verb of Matthew 28:19 ('make disciples of all nations'). After the Lystra stoning, Paul and Barnabas continue to the next city and fulfill the Great Commission's making-disciples mandate. The mission that passes through apparent death produces abundant life — the resurrection pattern operating at the missional level: suffering followed by fruitfulness.</p>",
"22": "<p>'Strengthening the souls of the disciples, encouraging them to continue in the faith, and saying that through many tribulations we must enter the kingdom of God.' The 'must' (dei) of tribulation is the same divine necessity that governed Jesus's own path: 'Was it not necessary (edei) that the Christ should suffer these things and enter into his glory?' (Luke 24:26). The disciples' path into the kingdom runs through the same tribulations their Lord endured — not as punishment but as the pattern of life through death that the resurrection has established as the shape of the Christian way.</p>",
"23": "<p>'And when they had appointed elders for them in every church, with prayer and fasting they committed them to the Lord in whom they had believed.' The appointment of elders with prayer and fasting echoes the commissioning of Paul and Barnabas in Acts 13:3 (prayer and fasting before sending). The risen Lord is the one to whom the communities are 'committed' (paratithēmi — entrusted, as a deposit). The phrase 'in whom they had believed' (eis hon pepisteukeisin) — the Lord Jesus Christ as the object of faith — makes the elder appointment an act of handing the community back to its true Shepherd (John 10:11; 1 Pet 5:4).</p>",
"24": "<p>The return journey through Pisidia to Pamphylia traces the first journey's route in reverse — pastoral consolidation following initial proclamation. The risen Lord's mission moves in both directions: forward into new territory, backward in strengthening and organizing what has been planted. The pattern mirrors Jesus's own ministry: he did not merely pass through but returned to places he had visited (Luke 8:1; 13:22), forming a community that would persist after his departure.</p>",
"25": "<p>Perga — where John Mark had left the mission earlier (Acts 13:13) — is now the site of new proclamation before departure to Attalia. The visit to Perga on the return journey may reflect Paul's pastoral awareness of incomplete work: the city where the mission had been interrupted by a companion's defection now receives the word more fully. The risen Lord's mission does not skip cities where difficulties occurred but circles back to complete what was begun.</p>",
"26": "<p>'From there they sailed to Antioch, where they had been commended to the grace of God for the work that they had now completed.' The theological framing of the journey's end: they were 'commended to the grace of God' (Acts 13:3) for a work now declared 'completed' (plērōsantes — fulfilled). The grace of God (charis tou theou) is the power that began, sustained, and completed the first missionary journey. The risen Lord accomplishes his mission through his grace, not through the apostles' strength.</p>",
"27": "<p>'And when they arrived and gathered the church together, they declared all that God had done with them, and how he had opened a door of faith to the Gentiles.' The report to the Antioch church — 'all that God had done with them' — makes the mission's subject God rather than Paul and Barnabas. The passive framing ('God had done with them') is the consistent theological posture: the apostles are instruments, God is agent. The 'door of faith opened to the Gentiles' echoes Jesus's parable of the door (John 10:9 — 'I am the door; if anyone enters by me, he will be saved'). The risen Lord is the door he opens.</p>",
"28": "<p>'And they remained no little time with the disciples.' The extended stay in Antioch — Luke's 'no little time' (ouk oligon chronon) — provides the community consolidation and pastoral relationship that the rapid first-journey travel could not. The returned missionaries do not immediately depart for new territory but invest in the base community. Jesus had spent extended time with his disciples before his departure (John 14–17 — the extended farewell discourse); the apostles model the same deep pastoral investment in their home community before the next phase of mission."
},
"15": {
"1": "<p>The Judaizing teachers who come from Judea teach that circumcision is required for salvation — 'unless you are circumcised according to the custom of Moses, you cannot be saved.' The insertion of circumcision as a salvation requirement places a human act (the rite of covenant entry) alongside grace as a condition of salvation. The controversy is fundamentally christological: if Christ's death and resurrection are sufficient for justification (as Peter will argue in v. 11), then circumcision is neither necessary nor appropriate as an additional condition. The Jerusalem council is convened to determine whether Jesus's work is complete or requires human supplement.</p>",
"2": "<p>'And after Paul and Barnabas had no small dissension and debate with them, Paul and Barnabas were appointed to go up to Jerusalem to the apostles and the elders about this question.' The 'no small dissension' (staseōs kai zētēseōs ouk oligēs) — serious conflict — makes the council necessary. The apostolic community discerns together rather than Paul and Barnabas simply declaring the answer. Jesus's promise of the Spirit's guidance ('he will guide you into all the truth,' John 16:13) is exercised through communal deliberation rather than private revelation, establishing the pattern of conciliar discernment.</p>",
"3": "<p>The delegation passes through Phoenicia and Samaria, 'describing in detail the conversion of the Gentiles, and bringing great joy to all the brothers.' The Gentile conversions that the Judaizing teachers view as problematic are received with 'great joy' by the diaspora communities along the route — joy being the signature response to the gospel's fulfillment of God's promises (Luke 2:10; 15:7, 10, 32; Acts 8:8; 13:52). The risen Lord's embrace of Gentiles is experienced as good news by those not invested in the circumcision requirement.</p>",
"4": "<p>'They were welcomed by the church and the apostles and the elders, and they declared all that God had done with them.' The Jerusalem reception of the delegation — welcomed by all three components of the mother church's leadership — frames the council positively before the controversy is engaged. The declaration is again: 'all that God had done with them' — the divine subject of the mission's framing establishes the theological foundation from which the council will operate. What God has done cannot simply be undone by human legislative addition.</p>",
"5": "<p>The 'believers who belonged to the party of the Pharisees' insist that Gentile converts must be circumcised and keep the law of Moses. The Pharisaic believers represent the most consistent position in Second Temple Judaism: covenant membership requires covenant sign. Their insistence is internally coherent within a pre-resurrection framework. What they have not yet fully grasped is the christological argument: if the Messiah has come, died, and risen — if the Spirit has been poured out on uncircumcised Gentiles — what does covenant entry now require? The council must think through the resurrection's implications for the law of Moses.</p>",
"6": "<p>The apostles and elders gather to 'consider this matter' (idein peri tou logou toutou) — the deliberative assembly of the whole community's leadership to weigh a theological controversy. The pattern echoes Acts 6 (the apostles gathering to address the Hellenist-Hebrew food distribution controversy) and anticipates the church's ongoing conciliar tradition. Jesus had promised: 'where two or three are gathered in my name, there am I among them' (Matt 18:20), and the Spirit's presence in the council's deliberation is the risen Lord's promised presence.</p>",
"7": "<p>Peter's recollection of the Cornelius event — 'in the early days God made a choice among you, that by my mouth the Gentiles should hear the word of the gospel and believe' — frames the Cornelius decision as God's choice through Peter, not Peter's independent initiative. This is the third telling of the Cornelius story in Acts (10:1–48; 11:4–17; 15:7–11), each time reinforcing its theological weight: the Gentile mission has divine authorization demonstrated by the Spirit's sovereign action.</p>",
"8": "<p>'And God, who knows the heart, bore witness to them, by giving them the Holy Spirit just as he did to us.' The God 'who knows the heart' (kardiognōstēs — heart-knower) — a divine attribute Peter uses in Acts 1:24 for the Lord who knows which candidate to choose. The Spirit's gift to uncircumcised Gentiles is the heart-knower's verdict on their standing before him: God's internal knowledge of their faith (not their circumcision status) determined his action. The risen Lord's Spirit, given to those who believe, is the ultimate validation that transcends external rite.</p>",
"9": "<p>'And he made no distinction between us and them, having cleansed their hearts by faith.' The 'no distinction' (ouden diekrinen) echoes the Spirit's command to Peter: 'making no distinction' (mēden diakrinanta, 11:12). The cleansing is 'by faith' (tē pistei) — the instrument of purification is not water, not circumcision, not ritual, but faith. The risen Christ is the object of faith that cleanses; the Spirit is the agent of cleansing; circumcision has been made irrelevant to the transaction.</p>",
"10": "<p>'Now, therefore, why are you putting God to the test by placing a yoke on the neck of the disciples that neither our fathers nor we have been able to bear?' Peter frames circumcision-requirement as testing God — the same phrase used for Israel's wilderness testing of God (Exod 17:7; Acts 5:9) and for satanic temptation (Matt 4:7; Luke 4:12). The 'yoke' (zygon) of the law is the burden Jesus had addressed in Matthew 11:28–30: 'Come to me, all who labor and are heavy laden... For my yoke is easy and my burden is light.' Adding the Mosaic yoke to Christ's easy yoke contradicts the gospel's invitation.</p>",
"11": "<p>'But we believe that we will be saved through the grace of the Lord Jesus, just as they will.' Peter's climactic statement is the council's theological center: salvation through the grace of the Lord Jesus alone — the same grace that saves Gentiles saves Jews. The reversal is radical: not Gentiles must be saved like Jews (by circumcision + faith), but Jews are saved like Gentiles (by faith in Christ's grace alone). The risen Lord's grace is the universal and exclusive basis of salvation, applying to both covenant people and Gentiles identically.</p>",
"12": "<p>Paul and Barnabas's report of 'signs and wonders God had done through them among the Gentiles' — the assembly falls silent and listens. The silence of the entire assembly (epigō pān to plēthos) before the testimony of divine signs is the appropriate response to divine action: the Gentile miracles are the risen Lord's validation of the Gentile mission, his visible endorsement of what the Judaizers questioned. The risen Lord who 'bore witness to the word of his grace' (14:3) through signs now gives his verdict through his apostles' testimony.</p>",
"13": "<p>James speaks after Paul and Barnabas — the brother of the Lord and leader of the Jerusalem church has the last word before the council's decision. His authority in the Jerusalem community is the context for his interpretive move: applying Amos 9:11–12 to the Gentile mission. The brother of Jesus, who was a skeptic during Jesus's ministry (John 7:5) and became a believer only after the resurrection (1 Cor 15:7), is now the authoritative interpreter of how Jesus's resurrection fulfills Israel's scripture.</p>",
"15": "<p>James cites the prophets: 'And with this the words of the prophets agree.' The appeal to prophetic scripture after the testimony of divine action (signs and wonders) is the double validation of the Gentile mission: what God has done confirms what the prophets foretold. The risen Lord's mission does not contradict Israel's scriptures but fulfills them — the hermeneutical move the disciples learned from the risen Jesus himself on the Emmaus road (Luke 24:27) and in the upper room (24:44–47).</p>",
"16": "<p>'After this I will return, and I will rebuild the tent of David that has fallen; I will rebuild its ruins, and I will restore it.' James quotes Amos 9:11 (LXX) — the promise of the restoration of David's fallen tent. The 'tent of David' is the Davidic dynasty and its temple-connected royal theology; James identifies Jesus as the Davidic king in whom this restoration is occurring. The risen Jesus is the one through whom David's collapsed royal line is rebuilt — not physically (the Davidic monarchy remains dissolved) but eschatologically, as the Davidic Messiah who reigns at God's right hand (Acts 2:30–36).</p>",
"17": "<p>'That the remnant of mankind may seek the Lord, and all the Gentiles who are called by my name.' The purpose of David's tent restoration (v. 16) is that the Gentiles — 'all the Gentiles who are called by my name' — may seek the Lord. The LXX of Amos 9:12 (which James quotes) reads 'all the Gentiles' where the Hebrew reads 'Edom'; the LXX reading makes the Gentile inclusion explicit. James's use of the LXX reading is not a proof-text error but a Spirit-guided recognition that the LXX preserves the theological intent: the Davidic Messiah's restoration includes the nations called by God's own name. Christians at Antioch were the first called by that name (11:26).</p>",
"18": "<p>'Known from of old.' The Gentile inclusion is not a late theological improvisation but was known to God 'from of old' (ap' aiōnos) — from eternity. The risen Lord's embrace of the Gentiles is not a response to Israel's rejection (contra some supersessionist readings) but part of the eternal divine plan. Paul will develop this theme in Ephesians 3:4–6 ('the mystery of Christ, which was not made known to the sons of men in other generations... that the Gentiles are fellow heirs') and Romans 9–11. James's citation establishes that the plan was ancient, not novel.</p>",
"19": "<p>'Therefore my judgment is that we should not trouble those of the Gentiles who turn to God.' James's verdict — 'not trouble' (mē parenochein) the Gentile believers — is a decisive ruling against circumcision as a condition of salvation. The verb 'trouble' (parenochleō) is a strong term: to harass, burden, oppress. Adding circumcision to the faith required for salvation is to harass people whom God has already accepted. James's ruling protects the Gentile believers from theological oppression in the name of the risen Lord who accepted them.</p>",
"20": "<p>The four conditions of the Jerusalem decree — abstain from things polluted by idols, from sexual immorality, from what has been strangled, and from blood — are minimum requirements enabling table fellowship between Jewish and Gentile believers, not conditions of salvation. The decree does not add to the faith required for salvation but addresses the practical conditions for the mixed community's common life. The risen Lord's community must be able to eat together (the central sign of the new covenant) across the Jewish-Gentile boundary.</p>",
"21": "<p>'For from ancient generations Moses has been preached in every city, and is read every Sabbath in the synagogues.' James's rationale for the minimal requirements: Jewish believers throughout the diaspora have deep sensitivities formed by lifelong synagogue formation, and the decree's minimal restrictions honor those sensitivities without burdening Gentile believers with circumcision. The risen Lord's community lives in real social contexts with real historical formations; the decree is pastoral wisdom for mixed communities navigating real differences.</p>",
"22": "<p>The Jerusalem community's decision to send Judas and Silas with Paul and Barnabas — 'leading men among the brothers' — makes the decree a communal action, not merely apostolic edict. The broadening of the delegation from two (Paul and Barnabas) to four ensures both Jerusalem and Antioch are representatively invested in the decree's delivery. The risen Lord's community governs itself through representative leadership, not unilateral apostolic decree — consistent with Jesus's promise of the Spirit's communal guidance.</p>",
"23": "<p>The letter begins: 'The brothers, both the apostles and the elders, to the brothers who are of the Gentiles in Antioch and Syria and Cilicia, greetings.' The formal letter's address reflects the equality of 'brothers' across the Jewish-Gentile boundary: those who send and those who receive share the same kinship in the risen Lord. The geographical scope — Antioch, Syria, and Cilicia — covers the primary areas of Paul's Gentile mission and demonstrates that the council's ruling applies to the whole Pauline mission territory.</p>",
"24": "<p>'Since we have heard that some persons have gone out from us and troubled you with words, unsettling your minds, although we gave them no instructions' — the council explicitly disavows the Judaizing teachers: they were not authorized by the Jerusalem community. The risen Lord's community publicly corrects the misrepresentation of its own authority: those who claimed Jerusalem's backing for circumcision-requirement did not have it. The correction protects Gentile believers from continuing confusion about what the Jerusalem community actually taught.</p>",
"25": "<p>'It has seemed good to us, having come to one accord, to choose men and send them to you with our beloved Barnabas and Paul.' The communal decision ('it has seemed good to us, having come to one accord') mirrors the Spirit-community formula of v. 28. The 'one accord' (homothumadon) that characterized the pre-Pentecost disciples (1:14) and the post-Pentecost community (2:46; 4:24) is the mark of Spirit-guided consensus. The risen Lord's community does not vote by majority but discerns to unanimous agreement.</p>",
"26": "<p>'Men who have risked their lives for the name of our Lord Jesus Christ.' Paul and Barnabas are commended for the Lystra stoning (Acts 14:19) and all the violence of the first journey — the suffering that marks authentic apostolic witness. Jesus had said: 'Blessed are you when others revile you and persecute you... on my account' (Matt 5:11). The decree commends those who have borne the cost of the name — their suffering validates their authority to carry the decree about the name's sufficiency for salvation.</p>",
"27": "<p>Judas and Silas are sent to 'report the same things by word of mouth' — the written decree is supplemented by personal testimony. The pairing of written word and personal witness mirrors the apostolic pattern: the risen Lord gave written commission (the Gospels and Epistles) but also sent personal witnesses (the apostles). The 'same things' confirmed verbally that the letter declares in writing ensures that the decree cannot be misread or misrepresented in transmission.</p>",
"28": "<p>'For it has seemed good to the Holy Spirit and to us.' The council's supreme christological claim: the Spirit and the community have reached the same judgment. The Holy Spirit — the risen Lord's gift and presence in the community — is the first subject of the decision; the community is the secondary agent. The risen Lord governs his community through the Spirit he promised (John 14:16–17; 16:13) and the community that receives the Spirit's guidance. This is the shape of authority in the risen Lord's community: Spirit-led conciliar discernment.</p>",
"29": "<p>The four conditions restated: abstain from what has been sacrificed to idols, from blood, from what is strangled, and from sexual immorality. The conditions form the minimum table-fellowship framework enabling the mixed community to eat together — the primary form of the new covenant community's common life. The risen Lord whose body and blood are shared in the Eucharist creates the community that eats together across every human boundary; the decree protects the integrity of that common table.</p>",
"30": "<p>'So when they were sent off, they went down to Antioch, and having gathered the congregation together, they delivered the letter.' The delivery of the decree to the gathered congregation is a public communal event — not a private communication to leaders but a community proclamation. The full assembly hears the Jerusalem council's ruling: the risen Lord's community governs itself through transparent communal communication, not clerical management of information.</p>",
"31": "<p>'And when they had read it, they rejoiced because of its encouragement.' The community's response is joy (echárēsan) — the same response to the gospel throughout Luke-Acts (Luke 2:10; Acts 8:8; 13:52). The decree's content — freedom from circumcision requirement, salvation through grace alone — is experienced as the gospel's good news extending into the community's practical life. The risen Lord's sufficiency for salvation is cause for the joy that marks his kingdom's arrival.</p>",
"32": "<p>Judas and Silas 'being themselves prophets, encouraged and strengthened the brothers with many words.' The prophetic gift of encouragement and strengthening is the Spirit's pastoral provision for the community navigating theological controversy. Jesus had promised that the Helper (Paraclete — the Encourager, John 14:16) would come; Judas and Silas embody the paracletic ministry of encouragement (parakaleō — 'encouraged') that the Spirit enables. The community emerging from controversy needs strengthening, not just resolution.</p>",
"33": "<p>Judas and Silas's return to Jerusalem — 'in peace' (met' eirēnēs) — signals the restoration of communal peace that the Judaizing controversy had threatened. Peace (eirēnē) is the risen Lord's characteristic greeting and gift (Luke 24:36; John 20:19, 21, 26); the community's peace after the council is the risen Lord's peace at work in his body. The Antioch and Jerusalem communities are reconciled as the Jerusalem community officially endorses the Gentile mission's terms.</p>",
"34": "<p>Verse 34, present in some manuscripts ('But it seemed good to Silas to remain there'), is widely considered a scribal addition explaining why Silas is still available in v. 40. The best manuscripts omit it; Luke likely assumed readers would understand Silas had returned to Antioch independently.</p>",
"35": "<p>'But Paul and Barnabas remained in Antioch, teaching and preaching the word of the Lord, with many others also.' The continued mission in Antioch — teaching and preaching (didaskontes kai euangelizomenoi) — is the double task of the apostolic community: forming believers in the word (teaching) and extending the word to new hearers (preaching). Jesus had commanded both (Matt 28:19–20: 'make disciples... teaching them'; Luke 24:47: 'repentance... be proclaimed'). The Antioch community's post-council activity is the mission at its fullest.</p>",
"36": "<p>'Let us return and visit the brothers in every city where we proclaimed the word of the Lord, and see how they are.' Paul's proposed revisit mission is pastoral rather than evangelistic: the concern is 'how they are' (pōs echousin) — the condition of communities already formed. Jesus had modeled this pastoral return: he revisited communities he had already visited (Luke 8:1), and he sent the Seventy to places 'where he himself was about to go' (Luke 10:1), cultivating rather than merely planting. The risen Lord's mission includes consolidation and pastoral care, not only frontier expansion.</p>",
"37": "<p>Barnabas wants to take John Mark — the cousin (Col 4:10) who had left the mission at Perga (Acts 13:13). Barnabas's instinct toward restoration echoes his character as 'son of encouragement' (4:36) and mirrors the parable of the prodigal son (Luke 15:20 — 'while he was still a long way off, his father saw him and felt compassion'). The risen Lord's community is constituted by restoration — the God who restores the fallen (Peter, Paul, now potentially John Mark) forms his servants toward the same restorative character.</p>",
"38": "<p>Paul judges that John Mark, who had 'withdrawn from them in Pamphylia and had not gone with them to the work,' should not be taken again. Paul's judgment is not merciless but mission-focused: the hardships of the second journey require demonstrated commitment. The contrast between Barnabas's pastoral instinct and Paul's mission-integrity concern reflects a genuine tension within the community of the risen Lord — both are serving real values the Lord himself embodies (the Good Shepherd who goes to the lost vs. the Lord who requires counting the cost, Luke 14:28).</p>",
"39": "<p>'And there arose a sharp disagreement, so that they separated from each other.' The paroxysmos (sharp disagreement, paroxysm) between Paul and Barnabas is the first major interpersonal conflict between the risen Lord's leading servants in Acts. Luke does not harmonize or excuse the conflict: real people with real disagreements serve the risen Lord. The separation, though painful, produces two missionary teams where there had been one — a providential multiplication (Paul + Silas, Barnabas + Mark) that serves the mission's scope.</p>",
"40": "<p>'But Paul chose Silas and departed, having been commended by the brothers to the grace of the Lord.' The 'commendation to the grace of the Lord' — the same phrase used to start the first journey (14:26: 'commended to the grace of God') — frames the second journey's beginning under the same divine patronage. Silas, a Jerusalem prophet (v. 32) and Roman citizen (Acts 16:37), brings both prophetic charisma and legal protection to the new team. The risen Lord's grace, not the team's agreement, is the mission's foundation.</p>",
"41": "<p>'And he went through Syria and Cilicia, strengthening the churches.' The second journey begins with pastoral consolidation — strengthening communities already formed — before pressing into new territory. The risen Lord's mission pattern is disciplined: strengthen what has been planted before expanding the frontier. Syria and Cilicia were Paul's home territory (Tarsus, in Cilicia; Damascus and Antioch, in Syria); the strengthening of home communities is itself an act of missional faithfulness before the westward expansion of Acts 16–18."
}
}

def main():
    existing = load_comm('mkt-christ', 'acts')
    merge_comm(existing, ACTS_CH)
    save_comm('mkt-christ', 'acts', existing)
    for ck in ['14', '15']:
        count = len(existing.get(ck, {}))
        print(f'Acts {ck}: {count} verses.')

if __name__ == '__main__':
    main()
